from flask import Flask, redirect, request, session, jsonify
import requests
import os

app = Flask(__name__)
app.secret_key = os.urandom(24)

CLIENT_ID = 'your_client_id'
REDIRECT_URI = 'http://localhost:5000/callback'
AUTHORIZATION_ENDPOINT = 'https://authorization-server.com/auth'
TOKEN_ENDPOINT = 'https://authorization-server.com/token'

@app.route('/')
def index():
    return 'Welcome to the Admin Dashboard! <a href="/login">Login</a>'

@app.route('/login')
def login():
    authorization_url = f"{AUTHORIZATION_ENDPOINT}?client_id={CLIENT_ID}&redirect_uri={REDIRECT_URI}&scope=openid&response_type=id_token"
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    id_token = request.args.get('id_token')
    if id_token:
        session['id_token'] = id_token
        return redirect('/profile')
    return 'Login failed', 400

@app.route('/profile')
def profile():
    if 'id_token' in session:
        return jsonify({'id_token': session['id_token']})
    return redirect('/')

